css:
.loader {color: var(--loader-color, #0891b2);
  --loader-secondary-color: #22d3ee;
  --loader-bg: #ffffff;
  display: inline-grid;
  width: 40px;
  aspect-ratio: 1;
}.loader:before,.loader:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
  background: repeating-conic-gradient(var(--loader-color, #0891b2) 0 60deg,var(--loader-secondary-color, #22d3ee) 0 120deg);
  animation: l6 4s linear infinite;
}.loader:before {translate: 0 -100%;
}.loader:after {padding: 20%;
  mask: conic-gradient(currentColor 0 0) content-box exclude,conic-gradient(currentColor 0 0);
  animation-direction: reverse;
}@keyframes l6 {to{rotate: 1turn;
}}
